3276     FMF = FPOp->getFastMathFlags();
3277     DemandedMask = adjustDemandedMaskFromFlags(DemandedMask, FMF);
3278   }
3279 
3280   switch (I->getOpcode()) {
3281   case Instruction::Select: {
3282     // TODO: Can we infer which side it came from based on adjusted result
3283     // class?
3284     KnownFPClass KnownRHS =
3285         computeKnownFPClass(I->getOperand(2), DemandedMask, CxtI, Depth + 1);
3286     if (KnownRHS.isKnownNever(DemandedMask))
3287       return I->getOperand(1);
3288 
3289     KnownFPClass KnownLHS =
3290         computeKnownFPClass(I->getOperand(1), DemandedMask, CxtI, Depth + 1);
3291     if (KnownLHS.isKnownNever(DemandedMask))
3292       return I->getOperand(2);
3293 
3294     adjustKnownFPClassForSelectArm(KnownLHS, I->getOperand(0), I->getOperand(1),
3295                                    /*Invert=*/false, SQ, Depth);
3296     adjustKnownFPClassForSelectArm(KnownRHS, I->getOperand(0), I->getOperand(2),
3297                                    /*Invert=*/true, SQ, Depth);
