3308       Known = computeKnownFPClass(I, DemandedMask, CxtI, Depth + 1);
3309       break;
3310     }
3311 
3312     FastMathFlags FabsFMF = cast<FPMathOperator>(FNegSrc)->getFastMathFlags();
